1	import { test, expect } from '@playwright/test';
2	import path from 'node:path';
3	import { fileURLToPath } from 'node:url';
4	
5	// Marketing assets — feature-area screenshots referenced by
6	// website/content/features/_index.md. Written directly into
7	// website/static/ui/ with the exact filenames the Hugo site renders.
8	const __dirname = path.dirname(fileURLToPath(import.meta.url));
9	const WEBSITE_UI_DIR = path.resolve(__dirname, '../../../../../website/static/ui');
10	
11	// DDx Server UI — visual regression screenshots
12	// These capture each page for visual review and regression detection.
13	// Run: bunx playwright test e2e/screenshots.spec.ts --update-snapshots
14	// to update baselines after intentional changes.
15	//
16	// Dark/light parity is a FEAT-008 frontend-design gate
17	// (docs/helix/01-frame/concerns.md#frontend-design). Every page is
18	// snapshotted in both modes; any theme-specific palette drift fails CI.
19	//
20	// Per-project routes resolve their node/project IDs at runtime against
21	// the fixture-backed Go DDx server (see playwright.config.ts) so the
22	// screenshots render seeded fixture data rather than the developer's
23	// live .ddx/ state.
24	
25	// Resolve fixture node + project IDs from the live harness. The fixture
26	// project is the workspace under a `mktemp -d -t ddx-e2e-XXXXXX` path —
27	// other entries in /api/projects (carried over from developer-local state)
28	// must not be picked up here.
29	async function getFixtureIds(
30		request: import('@playwright/test').APIRequestContext
31	): Promise<{ nodeId: string; projectId: string }> {
32		const nodeResp = await request.post('/graphql', {
33			data: { query: '{ nodeInfo { id name } }' }
34		});
35		const nodeBody = (await nodeResp.json()) as {
36			data: { nodeInfo: { id: string; name: string } };
37		};
38		const projectsResp = await request.get('/api/projects');
39		const projects = (await projectsResp.json()) as Array<{ id: string; name: string; path: string }>;
40		const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
41		if (!fixture) {
42			throw new Error(
43				`fixture server has no ddx-e2e-* project registered (got: ${projects
44					.map((p) => p.id)
45					.join(', ')})`
46			);
47		}
48		return { nodeId: nodeBody.data.nodeInfo.id, projectId: fixture.id };
49	}
