import { expect, test } from '@playwright/test';

// Sessions is no longer a standalone page — the route load() throws a 302
// redirect to /runs?layer=run (see
// src/routes/nodes/[nodeId]/projects/[projectId]/sessions/+page.ts), and the
// run-layer Runs page is what operators land on. These tests assert that the
// redirect contract holds: any client-side navigation or direct visit to the
// project-scoped /sessions URL ends up on the run-layer Runs view, with the
// layer filter applied.

const NODE_INFO = { id: 'node-abc', name: 'Test Node' };
const PROJECT_ID = 'proj-1';
const PROJECTS = [{ id: PROJECT_ID, name: 'Project Alpha', path: '/repos/alpha' }];
const SESSIONS_URL = `/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/sessions`;
const RUNS_LAYER_URL_RE = new RegExp(
	`/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/runs\\?(?:[^#]*&)?layer=run`
);

type RunNode = {
	id: string;
	layer: string;
	status: string;
	projectID: string;
	beadId: string | null;
	startedAt: string | null;
	durationMs: number | null;
	harness: string | null;
	queueInputs: string | null;
};

const sampleRun: RunNode = {
	id: 'run-001',
	layer: 'run',
	status: 'success',
	projectID: PROJECT_ID,
	beadId: 'ddx-sample',
	startedAt: '2026-04-22T12:00:00Z',
	durationMs: 4000,
	harness: 'codex',
	queueInputs: null
};

function runsPayload(rows: RunNode[]) {
	return {
		runs: {
			edges: rows.map((node) => ({ node, cursor: node.id })),
			pageInfo: { hasNextPage: false, endCursor: null },
			totalCount: rows.length
		}
	};
}

async function mockRunLayerEndpoints(page: import('@playwright/test').Page, rows: RunNode[]) {
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as { query: string };
		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
			});
		} else if (body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((node) => ({ node })) } } })
			});
		} else if (body.query.includes('ProjectRuns') || body.query.includes('runs(')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: runsPayload(rows) })
			});
		} else {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: {} })
			});
		}
	});
}

test('direct visit to /sessions redirects to /runs?layer=run', async ({ page }) => {
	await mockRunLayerEndpoints(page, [sampleRun]);

	await page.goto(SESSIONS_URL);

	await expect(page).toHaveURL(RUNS_LAYER_URL_RE);
	await expect(page.getByRole('heading', { name: 'Runs' })).toBeVisible();
	// Layer=run filter chip is active after the redirect.
	const layerRunChip = page.getByTestId('layer-chip-run');
	await expect(layerRunChip).toHaveAttribute('aria-pressed', 'true');
});

test('redirect preserves additional query params', async ({ page }) => {
	await mockRunLayerEndpoints(page, [sampleRun]);

	await page.goto(`${SESSIONS_URL}?harness=codex`);

	await expect(page).toHaveURL(RUNS_LAYER_URL_RE);
	await expect(page).toHaveURL(/harness=codex/);
});

test('redirected runs page expands a run-layer row to surface session detail', async ({ page }) => {
	await mockRunLayerEndpoints(page, [sampleRun]);

	await page.goto(SESSIONS_URL);
	await expect(page).toHaveURL(RUNS_LAYER_URL_RE);

	const row = page.locator(`[data-run-row="${sampleRun.id}"]`);
	await expect(row).toBeVisible();
	await row.click();

	// The expanded row mounts RunRowDetail which fetches the run detail; the
	// expansion indicator switches from ▸ to ▾.
	await expect(row).toContainText('▾');
});

